import re
from typing import Optional

def parse_response(response: str) -> dict:
    """Return {"beam": [...], "solution": str|None, "done": bool}."""
    sol = re.search(r"SOLUTION FOUND:.*?\nSOLUTION:\s*(.+?)(?=\n\n|\Z)",
                    response, re.DOTALL)
    if sol:
        return {"beam": [], "solution": sol.group(1).strip(), "done": True}

    cands = {m.group(1): m.group(2).strip()
             for m in re.finditer(
                 r"Candidate (\S+):\s*(.+?)(?=\nCandidate |\nScore |\nKEPT|\Z)",
                 response, re.DOTALL)}
    scores = {m.group(1): float(m.group(2))
              for m in re.finditer(r"Score (\S+):\s*([\d.]+)", response)}
    kept_m = re.search(r"KEPT:\s*([^\n]+)", response)
    kept = {k.strip() for k in kept_m.group(1).split(",")} if kept_m else set()
    beam = sorted(
        [{"id": cid, "description": cands.get(cid, ""), "score": scores.get(cid, 0.5)}
         for cid in kept if cid in cands],
        key=lambda c: c["score"], reverse=True,
    )
    return {"beam": beam, "solution": None, "done": not beam}

# Simplified SQL AoT orchestrator with external evaluation

import json, re

SQL_TEMPLATE = """SQL generation via beam search.
Schema: {schema}
Request: {request}
Iteration {iteration}/{max_iter} | Beam width: {beam_width}

Current beam (JSON):
{beam_json}

Output JSON with keys:
- "expansions": [{{"child_id":"...", "sql":"...", "desc":"..."}}]
- "pruning": {{"kept":[...], "pruned":[...]}}
- "termination": {{"status":"SOLUTION"|"CONTINUE", "sql":"..."}}
Evaluate expansions for valid column refs, correct join type, type compatibility.
"""

def external_score(sql: str, db_conn) -> float:
    """Score SQL by running EXPLAIN ANALYZE and counting errors."""
    try:
        rows = db_conn.execute(f"EXPLAIN ANALYZE {sql}")
        errors = sum(1 for r in rows if "error" in str(r).lower())
        return max(0.0, 1.0 - errors * 0.25)
    except Exception:
        return 0.0

def run_sql_aot(request, schema, llm_call, db_conn, beam_width=3, max_iter=5):
    beam = []
    for i in range(1, max_iter + 1):
        prompt = SQL_TEMPLATE.format(
            schema=schema, request=request, iteration=i,
            max_iter=max_iter, beam_width=beam_width,
            beam_json=json.dumps(beam, indent=2) or "[]",
        )
        raw = llm_call(prompt)
        try:
            parsed = json.loads(re.search(r"\{.*\}", raw, re.DOTALL).group(0))
        except Exception:
            break

        if parsed.get("termination", {}).get("status") == "SOLUTION":
            return parsed["termination"].get("sql", "")

        kept = set(parsed.get("pruning", {}).get("kept", []))
        beam = sorted(
            [{"id": e["child_id"], "sql": e["sql"], "desc": e["desc"],
              "score": external_score(e["sql"], db_conn)}
             for e in parsed.get("expansions", []) if e["child_id"] in kept],
            key=lambda c: c["score"], reverse=True
        )[:beam_width]

    return beam[0]["sql"] if beam else ""

# WRONG: grows without bound
def bad_state_update(all_history, new_candidates):
    all_history.extend(new_candidates)   # never discards pruned branches
    return all_history                   # prompt grows O(iterations * candidates)

# RIGHT: carry only survivors
def good_state_update(pruning_result, expansions, scores):
    kept_ids = set(pruning_result["kept"])
    return [
        {"id": e["id"], "description": e["desc"], "score": scores.get(e["id"], 0.5)}
        for e in expansions
        if e["id"] in kept_ids
    ]
